<?php
require_once __DIR__.'/../../config/auth.php';require_once __DIR__.'/../../config/database.php';require_once __DIR__.'/../../config/helper.php';require_admin();$pdo=db();$user=current_user();if(!$pdo){flash('error','Database belum terhubung.');redirect('admin/profile/index.php');}$s=$pdo->prepare('SELECT id,nama,username FROM users WHERE id=?');$s->execute([(int)$user['id']]);$row=$s->fetch();if(!$row){redirect('logout.php');}$errors=[];
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$nama=trim((string)($_POST['nama']??''));$username=strtolower(trim((string)($_POST['username']??'')));if(mb_strlen($nama)<3||mb_strlen($nama)>120)$errors[]='Nama harus 3–120 karakter.';if(!preg_match('/^[a-z0-9._-]{4,30}$/',$username))$errors[]='Format username tidak valid.';$c=$pdo->prepare('SELECT id FROM users WHERE username=? AND id<>?');$c->execute([$username,(int)$user['id']]);if($c->fetch())$errors[]='Username sudah digunakan.';if(!$errors){$u=$pdo->prepare('UPDATE users SET nama=?,username=? WHERE id=?');$u->execute([$nama,$username,(int)$user['id']]);$_SESSION['user']['name']=$nama;$_SESSION['user']['username']=$username;log_activity($pdo,(int)$user['id'],'Memperbarui profil admin');flash('success','Profil admin berhasil diperbarui.');redirect('admin/profile/index.php');}$row=['nama'=>$nama,'username'=>$username];}
$adminPageTitle='Edit Profil';$adminPageDescription='Perbarui nama dan username administrator.';$adminActive='';include __DIR__.'/../../includes/admin_header.php';
?>
<section class="admin-card admin-form-card"><div class="admin-card-head"><div><h2>Identitas Administrator</h2><p>Perubahan username digunakan pada login berikutnya.</p></div></div><?php if($errors):?><div class="notice"><ul class="error-list"><?php foreach($errors as $e):?><li><?=e($e)?></li><?php endforeach;?></ul></div><?php endif;?><form class="admin-form" method="post"><?=csrf_field()?><label>Nama Lengkap</label><input name="nama" value="<?=e($row['nama'])?>" required><label>Username</label><input name="username" value="<?=e($row['username'])?>" required pattern="[a-z0-9._-]+"><div class="admin-form-actions"><button class="btn">Simpan Profil</button><a class="btn ghost" href="<?=url('admin/profile/index.php')?>">Batal</a></div></form></section>
